  ('locality-7fec267e-moex-00320', 'locality-7fec267e', 'locality-7fec267e-moex-110-3082b5f1', 'sub-locality-7fec267e-04', NULL, 'single_choice', '關於法規命令之敘述，下列何者正確？', '["法規命令之內容應明列其法律授權之依據，不得逾越法律授權之範圍與立法精神，必要時，亦 可再委任下級機關訂定之", "行政機關訂定有關軍事、外交或其他重大事項且涉及國家機密或安全之法規命令，得不依行政 程序法所定程序為之", "行政機關擬訂法規命令時，得依職權採取各種適當方法，將公告內容廣泛周知", "法規命令依法應經上級機關核定者，應於發布後送上級機關核定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:22+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "301", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "一般行政"}'::jsonb, NULL),
